// ─── CATEGORIES ────────────────────────────────────────────────────────────
export const INIT_CATEGORIES = [
  { name: 'Grains',      icon: '🌾', color: '#b5600d', bg: '#fff3e6' },
  { name: 'Spices',      icon: '🌶️', color: '#c0392b', bg: '#fdecea' },
  { name: 'Oilseeds',    icon: '🥜', color: '#7d5a00', bg: '#fff8e1' },
  { name: 'Fiber Crops', icon: '🌸', color: '#6d3f8e', bg: '#f3e5f5' },
  { name: 'Fruits',      icon: '🍎', color: '#e67e22', bg: '#fff3e0' },
  { name: 'Vegetables',  icon: '🥦', color: '#27ae60', bg: '#e8f8ee' },
];

// "All" meta used for the catch-all category pill/sidebar item
export const ALL_META = { icon: '🏪', color: '#1a6b3a', bg: '#e8f8ee' };
